arguments.new_str:
using System.IO.Compression;
using System.Text;

class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now defaults to UTF-8 and sets
        // the language encoding flag (EFS/bit 11). The legacy Java consumer
        // expects Shift-JIS, so specify it explicitly.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: keyed service lookups no longer fall back
// to non-keyed registrations. Register with the expected key.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

